  1→//! Advisory file locking for `.shatter/` shared state files.
  2→//!
  3→//! Wraps `fs2::FileExt` (flock syscall) to prevent lost-update races when
  4→//! multiple shatter processes run concurrently. Locks are kernel-managed —
  5→//! released automatically on process exit, crash, or SIGKILL.
  6→
  7→use std::fs::File;
  8→use std::io;
  9→use std::path::{Path, PathBuf};
 10→
 11→use fs2::FileExt;
 12→
 13→/// RAII guard that holds an exclusive flock on a `.lock` sidecar file.
 14→/// The lock is released when the guard is dropped.
 15→pub struct FileLock {
 16→    _file: File,
 17→    lock_path: PathBuf,
 18→}
 19→
 20→impl FileLock {
 21→    /// Acquire an exclusive lock for `protected_path` (blocking).
 22→    ///
 23→    /// Creates a sidecar `.lock` file next to the protected path.
 24→    /// Blocks until the lock is available.
 25→    pub fn acquire(protected_path: &Path) -> io::Result<Self> {
 26→        let lock_path = lock_path_for(protected_path);
 27→        if let Some(parent) = lock_path.parent() {
 28→            std::fs::create_dir_all(parent)?;
 29→        }
 30→        let file = File::create(&lock_path)?;
 31→        file.lock_exclusive()?;
 32→        Ok(Self {
 33→            _file: file,
 34→            lock_path,
 35→        })
 36→    }
 37→
 38→    /// Try to acquire an exclusive lock without blocking.
 39→    ///
 40→    /// Returns `Ok(None)` if another process holds the lock.
 41→    pub fn try_acquire(protected_path: &Path) -> io::Result<Option<Self>> {
 42→        let lock_path = lock_path_for(protected_path);
 43→        if let Some(parent) = lock_path.parent() {
 44→            std::fs::create_dir_all(parent)?;
 45→        }
 46→        let file = File::create(&lock_path)?;
 47→        match file.try_lock_exclusive() {
 48→            Ok(()) => Ok(Some(Self {
 49→                _file: file,
 50→                lock_path,
 51→            })),
 52→            Err(e) if e.kind() == io::ErrorKind::WouldBlock => Ok(None),
 53→            // fs2 on Linux returns Other for EWOULDBLOCK on some kernels
 54→            Err(e) if e.raw_os_error() == Some(libc::EWOULDBLOCK) => Ok(None),
 55→            Err(e) => Err(e),
 56→        }
 57→    }
 58→
 59→    /// Path of the lock file (for diagnostics).
 60→    pub fn lock_path(&self) -> &Path {
 61→        &self.lock_path
 62→    }
 63→}
 64→
 65→/// Compute the `.lock` sidecar path for a given file.
 66→///
 67→/// `foo/bar.json` → `foo/bar.json.lock`
 68→fn lock_path_for(path: &Path) -> PathBuf {
 69→    let mut lock = path.as_os_str().to_owned();
 70→    lock.push(".lock");
 71→    PathBuf::from(lock)
 72→}
 73→
 74→#[cfg(test)]
 75→mod tests {
 76→    use super::*;
 77→    use std::sync::{Arc, Barrier};
 78→
 79→    #[test]
 80→    fn acquire_and_drop_releases_lock() {
 81→        let dir = tempfile::tempdir().unwrap();
 82→        let target = dir.path().join("state.json");
 83→
 84→        let guard = FileLock::acquire(&target).unwrap();
 85→        assert!(guard.lock_path().exists());
 86→        drop(guard);
 87→
 88→        // Can re-acquire after drop
 89→        let _guard2 = FileLock::acquire(&target).unwrap();
 90→    }
 91→
 92→    #[test]
 93→    fn try_acquire_returns_none_when_held() {
 94→        let dir = tempfile::tempdir().unwrap();
 95→        let target = dir.path().join("state.json");
 96→
 97→        let _guard = FileLock::acquire(&target).unwrap();
 98→        let result = FileLock::try_acquire(&target).unwrap();
 99→        assert!(result.is_none());
100→    }
101→
102→    #[test]
103→    fn concurrent_access_serialized() {
104→        let dir = tempfile::tempdir().unwrap();
105→        let counter_path = dir.path().join("counter.json");
106→        std::fs::write(&counter_path, "0").unwrap();
107→
108→        let n_threads = 8;
109→        let iterations = 50;
110→        let barrier = Arc::new(Barrier::new(n_threads));
111→        let counter_path = Arc::new(counter_path);
112→
113→        let handles: Vec<_> = (0..n_threads)
114→            .map(|_| {
115→                let barrier = Arc::clone(&barrier);
116→                let path = Arc::clone(&counter_path);
117→                std::thread::spawn(move || {
118→                    barrier.wait();
119→                    for _ in 0..iterations {
120→                        let _lock = FileLock::acquire(&path).unwrap();
121→                        let val: u64 = std::fs::read_to_string(&*path)
122→                            .unwrap()
123→                            .trim()
124→                            .parse()
125→                            .unwrap();
126→                        std::fs::write(&*path, (val + 1).to_string()).unwrap();
127→                    }
128→                })
129→            })
130→            .collect();
131→
132→        for h in handles {
133→            h.join().unwrap();
134→        }
135→
136→        let final_val: u64 = std::fs::read_to_string(&*counter_path)
137→            .unwrap()
138→            .trim()
139→            .parse()
140→            .unwrap();
141→        assert_eq!(
142→            final_val,
143→            (n_threads * iterations) as u64,
144→            "concurrent increments should not lose updates"
145→        );
146→    }
147→}
