698→/// Parse a target string: `<file>:<function>` or just `<file>`.
699→///
700→/// If there is no colon, the entire string is treated as a file path (analyze all functions).
701→fn parse_target(target: &str) -> Result<Target, String> {
702→    let (file_str, function) = match target.rsplit_once(':') {
703→        Some((f, func)) if !func.is_empty() => (f, Some(func.to_string())),
704→        _ => (target, None),
705→    };
706→
707→    let file = PathBuf::from(file_str);
708→
709→    let ext = file
710→        .extension()
711→        .and_then(|e| e.to_str())
712→        .ok_or_else(|| format!("cannot detect language: no file extension in '{file_str}'"))?;
713→
714→    let language = Language::from_extension(ext)
715→        .ok_or_else(|| format!("unsupported file extension '.{ext}' in '{file_str}'"))?;
716→
717→    Ok(Target {
718→        file,
719→        function,
720→        language,
721→    })
722→}
